mapper.select:
SELECT ROUND(IFNULL(SUM(amount) - SUM(refund_amount), 0)/100, 2) AS payAmount, IFNULL(COUNT(1), 0) AS payCount
FROM t_pay_order
WHERE 1=1
 AND state = #{state} 
 AND refund_state = #{refundState} 
 AND mch_no = #{mchNo} 
 AND created_at >= #{createTimeStart} 
 AND created_at <= #{createTimeEnd} 
;

SELECT COUNT(1) AS typeCount, ROUND(IFNULL(SUM(amount) - SUM(refund_amount), 0)/100, 2) AS typeAmount, way_code as wayCode
FROM t_pay_order
WHERE 1=1
 AND state = #{state} 
 AND refund_state = #{refundState} 
 AND mch_no = #{mchNo} 
 AND created_at >= #{createTimeStart} 
 AND created_at <= #{createTimeEnd} 
GROUP BY way_code

SELECT DATE_FORMAT(FLOOR(created_at),'%m-%d') groupDate, ROUND(IFNULL(SUM(amount) - SUM(refund_amount), 0)/100, 2) AS payAmount,
ROUND(IFNULL(SUM(refund_amount), 0)/100, 2) AS refundAmount
FROM t_pay_order
WHERE  1=1
AND state in (2,5)
 AND mch_no = #{mchNo} 
 AND created_at >= #{createTimeStart} 
 AND created_at <= #{createTimeEnd} 
GROUP BY groupDate
ORDER BY groupDate desc

SELECT
    COUNT(1) AS submitOrderCount,
    ROUND(IFNULL(SUM(amount), 0)/100, 2) AS allAmount,
    SUM(CASE WHEN state = 2 THEN 1 ELSE 0 END) AS successOrderCount,
    ROUND(IFNULL(SUM(CASE WHEN state = 2 THEN amount ELSE 0 END), 0)/100, 2) AS successAmount,
    ROUND(IFNULL(SUM(CASE WHEN state = 2 THEN (amount - IFNULL(refund_amount, 0) - IFNULL(mch_fee_amount, 0)) ELSE 0 END), 0)/100, 2) AS mchIncome,
    ROUND(IFNULL(SUM(CASE WHEN state = 2 THEN 0 ELSE 0 END), 0)/100, 2) AS agentIncome,
    ROUND(IFNULL(SUM(CASE WHEN state = 2 THEN IFNULL(mch_fee_amount, 0) ELSE 0 END), 0)/100, 2) AS platformIncome,
    SUM(CASE WHEN state IN (0, 1, 3) THEN 1 ELSE 0 END) AS unpaidOrderCount,
    ROUND(IFNULL(SUM(CASE WHEN state IN (0, 1, 3) THEN amount ELSE 0 END), 0)/100, 2) AS unpaidAmount
FROM t_pay_order
WHERE 1=1
 AND mch_no = #{param.mchNo} 
 AND isv_no = #{param.isvNo} 
 AND app_id = #{param.appId} 
 AND way_code = #{param.wayCode} 
 AND state = #{param.state} 
 AND notify_state = #{param.notifyState} 
 AND pay_order_id = #{param.payOrderId} 
 AND mch_order_no = #{param.mchOrderNo} 
 AND channel_order_no = #{param.channelOrderNo} 
 AND created_at >= #{param.createTimeStart} 
 AND created_at <= #{param.createTimeEnd}
